// HealthInsuranceList.js - Danh sách BHYT
import React, { useState } from "react";
import { Card, CardBody, Container, Row, Col, InputGroup, Input, Button, Table } from "reactstrap";
import { useNavigate } from "react-router-dom";
import Header from "components/Headers/Header.js";

const HealthInsuranceList = () => {
    const navigate = useNavigate();
    const [searchTerm, setSearchTerm] = useState("");
    const [healthInsurances, setHealthInsurances] = useState([
        { id: 1, code: "BHYT003", name: "Nguyễn Văn A", location: "Hà Nội", expiry: "1/2/2025", currency: "VND", issueDate: "1/2/2025", issuePlace: "Hà Nội" },
        { id: 2, code: "BHYT004", name: "Nguyễn Văn A", location: "Hà Nội", expiry: "1/2/2024", currency: "VND", issueDate: "1/2/2024", issuePlace: "Hà Nội" },
        { id: 3, code: "BHYT005", name: "Nguyễn Văn A", location: "Hà Nội", expiry: "1/2/2020", currency: "VND", issueDate: "1/2/2020", issuePlace: "Hà Nội" }
    ]);

    const filteredHealthInsurances = healthInsurances.filter(item =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.code.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const handleDelete = (id) => {
        setHealthInsurances(healthInsurances.filter(item => item.id !== id));
    };

    return (
        <>
            <Header />
            <Container fluid className="mt-4">
                <Row className="mb-4">
                    <Col md="6">
                        <h3>Danh Sách Thẻ BHYT</h3>
                    </Col>
                    <Col md="3">
                        <InputGroup>
                            <Input
                                type="text"
                                placeholder="Tìm kiếm thẻ BHYT"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </InputGroup>
                    </Col>
                    <Col md="3" className="text-right">
                        <Button color="success" onClick={() => navigate("/admin/add-health-insurance")}>+ Thêm BHYT</Button>
                    </Col>
                </Row>

                <Card>
                    <CardBody>
                        <Table bordered hover responsive>
                            <thead>
                                <tr>
                                    <th>STT</th>
                                    <th>Mã</th>
                                    <th>Họ và tên</th>
                                    <th>Nơi đăng kí khám</th>
                                    <th>Giá trị sử dụng</th>
                                    <th>Mã số</th>
                                    <th>Ngày cấp</th>
                                    <th>Nơi cấp</th>
                                    <th>Hành động</th>
                                </tr>
                            </thead>
                            <tbody>
                                {filteredHealthInsurances.map((item, index) => (
                                    <tr key={item.id}>
                                        <td>{index + 1}</td>
                                        <td>{item.code}</td>
                                        <td>{item.name}</td>
                                        <td>{item.location}</td>
                                        <td>{item.expiry}</td>
                                        <td>{item.currency}</td>
                                        <td>{item.issueDate}</td>
                                        <td>{item.issuePlace}</td>
                                        <td>
                                            <Button color="danger" size="sm" onClick={() => handleDelete(item.id)}>Xoá</Button>
                                            <Button color="success" size="sm">Sửa</Button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </Table>
                    </CardBody>
                </Card>
            </Container>
        </>
    );
};

export default HealthInsuranceList;
